diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..6a4df9896 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -1981,6 +1981,8 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 	fz_try(ctx)
 	{
 		pixmap = fz_get_pixmap_from_image(ctx, image, &src_area, &local_ctm, &dx, &dy);
+		if (!pixmap)
+			return;

 		state[1].mask = fz_new_pixmap_with_bbox(ctx, NULL, bbox, NULL, 1);
 		fz_clear_pixmap(ctx, state[1].mask);

diff --git a/source/fitz/draw-device.c b/source/fitz/draw-device.c
index a537b41fb..e90f352c4 100644
--- a/source/fitz/draw-device.c
+++ b/source/fitz/draw-device.c
@@ -2001,9 +2001,11 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 		state[1].blendmode |= FZ_BLEND_ISOLATED;
 		state[1].scissor = bbox;

-		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES) && ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pixmap->w, pixmap->h))
+		if (!(devp->hints & FZ_DONT_INTERPOLATE_IMAGES))
 		{
 			int gridfit = !(dev->flags & FZ_DRAWDEV_FLAGS_TYPE3);
+			int pw = pixmap->w;
+			int ph = pixmap->h;
 			scaled = fz_transform_pixmap(ctx, dev, pixmap, &local_ctm, state->dest->x, state->dest->y, dx, dy, gridfit, &clip);
 			if (!scaled)
 			{
@@ -2018,6 +2020,9 @@ fz_draw_clip_image_mask(fz_context *ctx, fz_device *devp, fz_image *image, fz_ma
 				fz_drop_pixmap(ctx, pixmap);
 				pixmap = scaled;
 			}
+			
+			if (!ctx->tuning->image_scale(ctx->tuning->image_scale_arg, dx, dy, pw, ph))
+				break;
 		}

 #ifdef DUMP_GROUP_BLENDS

